mapper.select:
select i.*,
       i.policy_number as encryptPolicyNumber
from t_insurance i


        AND INSTR(i.policy_number,#{queryDTO.keyWord})


        AND i.insurance_type = #{queryDTO.insuranceType}


        AND i.enterprise_id = #{queryDTO.enterpriseId}


        AND i.deleted_flag = #{queryDTO.deletedFlag}


        AND i.module_type = #{queryDTO.moduleType}


        AND i.module_id = #{queryDTO.moduleId}


        AND i.module_id IN

            #{item}



        AND i.insurance_company_code = #{queryDTO.insuranceCompanyCode}


        and DATE_FORMAT(i.expire_date, '%Y-%m-%d') >= #{queryDTO.startDate}


        and DATE_FORMAT(i.expire_date, '%Y-%m-%d') <= #{queryDTO.endDate}


        and DATE_FORMAT(i.create_time, '%Y-%m-%d') >= #{queryDTO.createStartDate}


        and DATE_FORMAT(i.create_time, '%Y-%m-%d') <= #{queryDTO.createEndDate}



    ORDER BY i.expire_date DESC

SELECT COUNT(1) FROM t_insurance where module_id = #{moduleId} AND module_type = #{moduleType} AND deleted_flag
= #{deletedFlag}

    AND insurance_id != #{excludeId}

SELECT module_id vehicleId,SUM(insurance_amount) amount
FROM t_insurance
where deleted_flag = #{queryForm.deletedFlag}
and module_type = #{moduleType}
and DATE_FORMAT(create_time, '%Y-%m-%d') >= #{queryForm.startTime}
and DATE_FORMAT(create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and enterprise_id = #{queryForm.enterpriseId}
and module_id in

    #{item}

GROUP BY module_id
